const express = require('express');
const cors = require('cors');
const fs = require('fs');
const path = require('path');
const app = express();
const PORT = process.env.PORT || 3000;

// Определяем окружение: локально или на Render
const isLocal = !process.env.RENDER;
let puppeteer;
if (isLocal) {
    puppeteer = require('puppeteer');
} else {
    puppeteer = require('puppeteer-core');
}

app.use(cors());
app.use(express.json({ limit: '10mb' }));

// --- ЗАГРУЗКА ТОКЕНОВ (ДОБАВЛЕНО) ---
const tokensPath = path.join(__dirname, 'tokens.json');
let tokensData = { tokens: [] };
if (fs.existsSync(tokensPath)) {
    tokensData = JSON.parse(fs.readFileSync(tokensPath, 'utf8'));
}
function saveTokens() {
    fs.writeFileSync(tokensPath, JSON.stringify(tokensData, null, 2));
}

// --- УНИВЕРСАЛЬНЫЙ ЗАПУСК БРАУЗЕРА ---
async function launchBrowser() {
    console.log('Запускаем браузер. Локальный режим:', isLocal);
    if (isLocal) {
        return await puppeteer.launch({
            headless: true,
            args: ['--no-sandbox', '--disable-setuid-sandbox']
        });
    } else {
        const chromium = require('@sparticuz/chromium');
        return await puppeteer.launch({
            args: [
                ...chromium.args,
                '--no-sandbox',
                '--disable-setuid-sandbox',
                '--disable-dev-shm-usage',
                '--single-process'
            ],
            executablePath: await chromium.executablePath(),
            headless: true,
            ignoreHTTPSErrors: true
        });
    }
}

