// --- ШАБЛОН ДЛЯ РОДИТЕЛЬ-РЕБЁНОК ---
function buildParentChildHTML(data) {
    const { parent, child, resultHTML } = data;
    const escape = (str) => String(str).replace(/[&<>]/g, c => ({'&':'&amp;','<':'&lt;','>':'&gt;'})[c]);

    return `<!DOCTYPE html>
<html lang="ru">
<head>
    <meta charset="UTF-8">
    <title>Родитель-ребёнок — ${escape(parent.name)} & ${escape(child.name)}</title>
    <link rel="preconnect" href="https://fonts.googleapis.com">
    <link rel="preconnect" href="https://fonts.gstatic.com" crossorigin>
    <link href="https://fonts.googleapis.com/css2?family=Inter:opsz,wght@14..32,400;14..32,500;14..32,600;14..32,700&display=swap" rel="stylesheet">
    <style>
        * { margin:0; padding:0; box-sizing:border-box; }
        body {
            font-family: 'Inter', sans-serif;
            background: linear-gradient(170deg, #fdf6ef 0%, #f9efe2 30%, #f5e6d5 100%);
            color: #3b3b3b;
            line-height: 1.6;
            padding: 30px 20px;
            min-height: 100vh;
            display: flex; flex-direction: column; align-items: center;
            font-size: 1rem;
        }
        .container { max-width: 900px; width: 100%; margin: 0 auto; }
        .single-card {
            background: rgba(255,252,248,0.85);
            border: 1px solid rgba(180,150,120,0.25);
            border-radius: 18px;
            padding: 28px 32px;
            margin-bottom: 18px;
            box-shadow: 0 6px 18px rgba(140,110,70,0.06);
        }
        h1 { font-size: 2rem; font-weight: 700; color: #5b3e2b; text-align: center; margin-bottom: 6px; }
        .subtitle { text-align: center; font-size: 0.9rem; color: #8b7a6b; margin-bottom: 18px; }
        h2 { font-size: 1.35rem; font-weight: 600; color: #6b4a30; border-left: 4px solid #c9a27c; padding-left: 14px; margin: 20px 0 12px; }
        .footer { text-align: center; color: #8b7a6b; margin-top: 30px; font-size: 0.85rem; }
    </style>
</head>
<body>
<div class="container">
   <div style="text-align: center; margin-bottom: 10px;">
<img src="data:image/png;base64," alt="" width="554" height="409" />    <div class="single-card">
        <h1>👨‍👧 Родитель и Ребёнок</h1>
        <h2 style="text-align:center;">${escape(parent.name)} & ${escape(child.name)}</h2>
        <p class="subtitle">Даты рождения: ${escape(parent.date)} и ${escape(child.date)}</p>
        <div>${resultHTML}</div>
        <div class="footer">© Astra Numerology | Отчёт создан автоматически</div>
    </div>
</div>
</body>
</html>`;
}

// --- ГЕНЕРАЦИЯ PDF (ГЛАВНАЯ СТРАНИЦА) ---
app.post('/generate-pdf', async (req, res) => {
    try {
        const payload = req.body;
        console.log(`[${new Date().toISOString()}] Генерация PDF для ${payload.userName || 'неизвестного'}`);

        const html = buildReportHTML(payload);
        const browser = await launchBrowser();
        const page = await browser.newPage();
        await page.setContent(html, { waitUntil: 'networkidle0' });

        const pdfBuffer = await page.pdf({
            format: 'A4',
            printBackground: true,
            margin: { top: '0mm', bottom: '0mm', left: '0mm', right: '0mm' },
            displayHeaderFooter: false
        });

        await browser.close();

        res.setHeader('Content-Type', 'application/pdf');
        const rawFileName = `Матрица_${payload.userName.replace(/\s+/g, '_')}.pdf`;
        const encodedFileName = encodeURIComponent(rawFileName);
        res.setHeader('Content-Disposition', `attachment; filename*=UTF-8''${encodedFileName}`);
        res.send(pdfBuffer);

    } catch (error) {
        console.error('Ошибка при генерации PDF:', error);
        res.status(500).json({ error: 'Не удалось создать PDF' });
    }
});

